 512→#[cfg(test)]
 513→mod tests {
 514→    use super::*;
 515→
 516→    /// Send a single request and read the response.
 517→    fn send_recv(req_json: &str) -> Response {
 518→        let input = format!("{req_json}\n");
 519→        let mut output = Vec::new();
 520→        let handler = Handler::new(
 521→            input.as_bytes(),
 522→            &mut output,
 523→            io::sink(),
 524→        );
 525→        handler.run().expect("handler.run");
 526→        let output_str = String::from_utf8(output).expect("valid utf8");
 527→        let first_line = output_str.lines().next().expect("at least one response line");
 528→        serde_json::from_str(first_line).expect("valid JSON response")
 529→    }
 530→
 531→    /// Send multiple requests and return all responses.
 532→    fn conversation(requests: &[&str]) -> Vec<Response> {
 533→        let input = requests.join("\n") + "\n";
 534→        let mut output = Vec::new();
 535→        let handler = Handler::new(
 536→            input.as_bytes(),
 537→            &mut output,
 538→            io::sink(),
 539→        );
 540→        handler.run().expect("handler.run");
 541→        let output_str = String::from_utf8(output).expect("valid utf8");
 542→        output_str
 543→            .lines()
 544→            .filter(|l| !l.is_empty())
 545→            .map(|l| serde_json::from_str(l).expect("valid JSON response"))
 546→            .collect()
 547→    }
 548→
 549→    #[test]
 550→    fn handshake_returns_rust_language() {
 551→        let resp = send_recv(
 552→            r#"{"protocol_version":"0.1.0","id":1,"command":"handshake","capabilities":["analyze"]}"#,
 553→        );
 554→        assert_eq!(resp.status, "handshake");
 555→        assert_eq!(resp.language.as_deref(), Some("rust"));
 556→        assert_eq!(resp.frontend_version.as_deref(), Some(crate::protocol::FRONTEND_VERSION));
 557→    }
