  1→//! Static analyzer for Rust source files using the `syn` crate.
  2→//!
  3→//! Parses Rust source code and extracts function signatures, branch locations,
  4→//! symbolic conditions, and external dependencies for the Shatter protocol.
  5→//!
  6→//! ## Limitations
  7→//!
  8→//! - **No cross-file type resolution**: `syn` parses a single file. Struct definitions
  9→//!   from other modules/crates are not available — named types become `Opaque`.
 10→//! - **No trait resolution**: Cannot determine which trait impl a method call resolves to.
 11→//! - **No macro expansion**: Macros are not expanded; generated code is invisible.
 12→//! - **No const evaluation**: Constant references in conditions appear as `Unknown`.
 13→//! - **Limited generics**: Generic type parameters `T` are reported as `Unknown`.
 14→//!   Trait bounds are noted but don't refine the type.
 15→//! - **Pattern matching**: Literal, range, or-pattern, and variant patterns produce
 16→//!   symbolic conditions. Deeply nested or guarded patterns may still produce `None`.
 17→
 18→use std::collections::{HashMap, HashSet};
 19→use std::path::Path;
 20→
 21→use quote::ToTokens;
 22→use syn::spanned::Spanned;
 23→
 24→use crate::protocol::{
 25→    BinOpKind, BranchInfo, BranchType, ComplexKind, ConstValue, DependencyKind,
 26→    ExternalDependency, FunctionAnalysis, LiteralValue, ParamInfo, SymExpr, TypeInfo, UnOpKind,
 27→};
 28→
 29→/// Error type for analysis failures.
 30→#[derive(Debug)]
 31→pub enum AnalyzeError {
 32→    FileNotFound(String),
 33→    ReadError(String),
 34→    ParseError(String),
 35→    FunctionNotFound(String),
 36→}
 37→
 38→impl std::fmt::Display for AnalyzeError {
 39→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 40→        match self {
 41→            Self::FileNotFound(p) => write!(f, "file not found: {p}"),
 42→            Self::ReadError(e) => write!(f, "failed to read file: {e}"),
 43→            Self::ParseError(e) => write!(f, "failed to parse file: {e}"),
 44→            Self::FunctionNotFound(n) => write!(f, "function not found: {n}"),
 45→        }
 46→    }
 47→}
 48→
 49→/// Analyze a Rust source file. If `function_name` is provided, return only that function.
 50→pub fn analyze_file(
 51→    file_path: &Path,
 52→    function_name: Option<&str>,
 53→) -> Result<Vec<FunctionAnalysis>, AnalyzeError> {
 54→    if !file_path.exists() {
 55→        return Err(AnalyzeError::FileNotFound(
 56→            file_path.display().to_string(),
 57→        ));
 58→    }
 59→
 60→    let source = std::fs::read_to_string(file_path)
 61→        .map_err(|e| AnalyzeError::ReadError(e.to_string()))?;
 62→
 63→    analyze_source(&source, function_name)
 64→}
 65→
 66→/// Analyze Rust source code from a string.
 67→pub fn analyze_source(
 68→    source: &str,
 69→    function_name: Option<&str>,
 70→) -> Result<Vec<FunctionAnalysis>, AnalyzeError> {
 71→    let file = syn::parse_file(source)
 72→        .map_err(|e| AnalyzeError::ParseError(e.to_string()))?;
 73→
 74→    // Collect struct and enum definitions in this file for type resolution.
 75→    let structs = collect_struct_defs(&file);
 76→    let enums = collect_enum_defs(&file);
 77→
 78→    let mut results = Vec::new();
 79→
 80→    for item in &file.items {
 81→        if let syn::Item::Fn(item_fn) = item {
 82→            let name = item_fn.sig.ident.to_string();
 83→
 84→            if let Some(target) = function_name
 85→                && name != target
 86→            {
 87→                continue;
 88→            }
 89→
 90→            results.push(analyze_function(item_fn, &structs, &enums));
 91→        }
 92→    }
 93→
 94→    if function_name.is_some() && results.is_empty() {
 95→        return Err(AnalyzeError::FunctionNotFound(
 96→            function_name.unwrap_or_default().to_string(),
 97→        ));
 98→    }
 99→
100→    Ok(results)
101→}
