 24→/// Errors that can occur during instrumentation.
 25→#[derive(Debug)]
 26→pub enum InstrumentError {
 27→    FileNotFound(String),
 28→    ReadError(String),
 29→    ParseError(String),
 30→}
 31→
 32→impl std::fmt::Display for InstrumentError {
 33→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 34→        match self {
 35→            Self::FileNotFound(p) => write!(f, "file not found: {p}"),
 36→            Self::ReadError(e) => write!(f, "failed to read file: {e}"),
 37→            Self::ParseError(e) => write!(f, "failed to parse file: {e}"),
 38→        }
 39→    }
 40→}
