 51→/// Instrument a Rust source file, optionally targeting a single function.
 52→///
 53→/// Returns the instrumented source code and the number of branches found.
 54→pub fn instrument_file(
 55→    path: &Path,
 56→    function_name: Option<&str>,
 57→) -> Result<InstrumentResult, InstrumentError> {
 58→    if !path.exists() {
 59→        return Err(InstrumentError::FileNotFound(
 60→            path.display().to_string(),
 61→        ));
 62→    }
 63→
 64→    let source = std::fs::read_to_string(path)
 65→        .map_err(|e| InstrumentError::ReadError(e.to_string()))?;
 66→
 67→    instrument_source(&source, function_name)
 68→}
