 97→/// Locate the shatter-rust-runtime crate by walking up from the shatter-rust binary.
 98→fn find_runtime_crate_path() -> Result<PathBuf, ExecuteError> {
 99→    // Try SHATTER_RUNTIME_PATH env var first (for testing and deployment).
100→    if let Ok(p) = std::env::var("SHATTER_RUNTIME_PATH") {
101→        let path = PathBuf::from(&p);
102→        if path.join("Cargo.toml").exists() {
103→            return Ok(path);
104→        }
105→    }
106→
107→    // Walk up from current exe to find shatter-rust-runtime as a sibling.
108→    if let Ok(exe) = std::env::current_exe() {
109→        let mut dir = exe.parent().map(Path::to_path_buf);
110→        for _ in 0..5 {
111→            if let Some(d) = &dir {
112→                let candidate = d.join("shatter-rust-runtime");
113→                if candidate.join("Cargo.toml").exists() {
114→                    return Ok(candidate);
115→                }
116→                dir = d.parent().map(Path::to_path_buf);
117→            }
118→        }
119→    }
120→
121→    Err(ExecuteError::FileError(
122→        "cannot locate shatter-rust-runtime crate; set SHATTER_RUNTIME_PATH".to_string(),
123→    ))
124→}
