 82→            file: file.to_string(),
 83→            function: Some(function_name.to_string()),
 84→            project_root: None,
 85→        })
 86→        .await
 87→        .expect("analyze command failed");
 88→
 89→    match response.result {
 90→        ResponseResult::Analyze { functions } => functions
 91→            .into_iter()
