  1→//! Float probe: detect integer-treating number parameters.
  2→//!
  3→//! TypeScript's `number` type covers both integers and floats. When shatter
  4→//! explores a function like `intToRoman(n: number)`, it generates floats where
  5→//! integers would be more useful. The float probe sends (float, floor) input
  6→//! pairs and compares execution results to classify each Float parameter as
  7→//! integer-treating, float-sensitive, or inconclusive.
  8→
  9→use std::collections::HashMap;
 10→use std::hash::{DefaultHasher, Hash, Hasher};
 11→
 12→use rand::Rng;
 13→use serde::{Deserialize, Serialize};
 14→use serde_json::{json, Value};
 15→
 16→use crate::protocol::ExecuteResult;
 17→use crate::types::{ParamInfo, TypeInfo};
 18→
 19→/// Number of (float, floor) probe pairs per parameter.
 20→pub const PROBE_COUNT: usize = 5;
 21→
 22→/// Fraction of probes that must agree for an IntegerTreating classification.
 23→pub const AGREEMENT_THRESHOLD: f64 = 0.8;
 24→
 25→/// When generating biased inputs, this fraction should be integers.
 26→pub const INTEGER_BIAS_RATIO: f64 = 0.8;
 27→
 28→/// How a Float parameter treats its fractional component.
 29→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 30→#[serde(rename_all = "snake_case")]
 31→pub enum FloatClassification {
 32→    /// The function floors/truncates the value — fractional part is ignored.
 33→    IntegerTreating,
 34→    /// The function's behavior depends on the fractional part.
 35→    FloatSensitive,
 36→    /// Not enough data to decide (e.g., all probes errored).
 37→    Inconclusive,
 38→}
 39→
 40→/// Result of probing a single Float parameter.
 41→#[derive(Debug, Clone, Serialize, Deserialize)]
 42→pub struct FloatProbeResult {
 43→    /// Index of this parameter in the function's param list.
 44→    pub param_index: usize,
 45→    /// Name of the parameter.
 46→    pub param_name: String,
 47→    /// Classification based on probe results.
 48→    pub classification: FloatClassification,
 49→    /// Number of (float, floor) pairs that agreed.
 50→    pub agreements: usize,
 51→    /// Total probes attempted.
 52→    pub total_probes: usize,
 53→    /// Float values where behavior diverged from floor (for reporting).
 54→    pub divergent_values: Vec<f64>,
 55→}
 56→
 57→/// Find indices of Float-typed parameters.
 58→pub fn float_param_indices(params: &[ParamInfo]) -> Vec<usize> {
 59→    params
 60→        .iter()
 61→        .enumerate()
 62→        .filter(|(_, p)| matches!(p.typ, TypeInfo::Float))
 63→        .map(|(i, _)| i)
 64→        .collect()
 65→}
 66→
 67→/// Generate `count` probe pairs for a specific Float parameter.
 68→///
 69→/// Each pair consists of (float_inputs, floor_inputs) where the target param
 70→/// gets a non-integer float in one and its floor in the other. All other
 71→/// params are filled with neutral defaults.
 72→pub fn generate_probe_pairs(
 73→    params: &[ParamInfo],
 74→    param_idx: usize,
 75→    count: usize,
 76→    rng: &mut impl Rng,
 77→) -> Vec<(Vec<Value>, Vec<Value>)> {
 78→    (0..count)
 79→        .map(|_| {
 80→            let float_val = generate_non_integer_float(rng);
 81→            let floor_val = float_val.floor();
 82→
 83→            let mut float_inputs = neutral_defaults(params);
 84→            let mut floor_inputs = neutral_defaults(params);
 85→
 86→            float_inputs[param_idx] = json!(float_val);
 87→            floor_inputs[param_idx] = json!(floor_val);
 88→
 89→            (float_inputs, floor_inputs)
 90→        })
 91→        .collect()
 92→}
 93→
 94→/// Check whether two executions agree: same branch path hash AND same return
 95→/// value (or both throw the same error type).
 96→pub fn executions_agree(a: &ExecuteResult, b: &ExecuteResult) -> bool {
 97→    let path_a = hash_branch_path(a);
 98→    let path_b = hash_branch_path(b);
 99→    if path_a != path_b {
100→        return false;
101→    }
102→
103→    match (&a.thrown_error, &b.thrown_error) {
104→        (Some(ea), Some(eb)) => ea.error_type == eb.error_type,
105→        (None, None) => a.return_value == b.return_value,
106→        _ => false,
107→    }
108→}
109→
110→/// Classify a parameter based on probe agreement ratio.
111→pub fn classify(agreements: usize, total: usize, threshold: f64) -> FloatClassification {
112→    if total == 0 {
113→        return FloatClassification::Inconclusive;
114→    }
115→    let ratio = agreements as f64 / total as f64;
116→    if ratio >= threshold {
117→        FloatClassification::IntegerTreating
118→    } else {
119→        FloatClassification::FloatSensitive
120→    }
121→}
122→
123→/// Build a bias map from probe results (param_index -> classification).
124→pub fn build_bias_map(results: &[FloatProbeResult]) -> HashMap<usize, FloatClassification> {
125→    results
126→        .iter()
127→        .map(|r| (r.param_index, r.classification))
128→        .collect()
129→}
