133→/// Generate a float that is guaranteed not to be an integer.
134→fn generate_non_integer_float(rng: &mut impl Rng) -> f64 {
135→    let candidates = [1.5, -2.7, 99.9, 0.3, -0.5, 3.17, 42.5, -17.3, 7.1, 256.99];
136→    let base = candidates[rng.random_range(0..candidates.len())];
137→    let offset = rng.random_range(0.01..0.49);
138→    let val: f64 = base + offset;
139→    if val.fract() == 0.0 { val + 0.1 } else { val }
140→}
