  1→//! End-to-end exploration tests using the real Rust frontend (shatter-rust).
  2→//!
  3→//! These tests validate the full analyze -> instrument -> execute pipeline
  4→//! against Rust example functions. Each test documents expected branches and
  5→//! verifies that executing with targeted inputs produces the expected return
  6→//! values and discovers distinct execution paths.
  7→//!
  8→//! NOTE: The orchestrator's `explore()` cannot drive the Rust frontend because
  9→//! `Command::Execute` in the core protocol lacks a `file` field, which the Rust
 10→//! frontend requires (it re-reads and compiles source per execution). These tests
 11→//! drive the pipeline manually via individual protocol commands instead.
 12→
 13→use std::collections::HashSet;
 14→use std::path::{Path, PathBuf};
 15→
 16→use shatter_core::frontend::{Frontend, FrontendConfig};
 17→use shatter_core::protocol::{Command as ProtoCommand, FunctionAnalysis, ResponseResult};
 18→
 19→/// Path to the Rust frontend binary, resolved from the workspace root.
 20→fn rust_frontend_path() -> PathBuf {
 21→    let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
 22→    let standalone = manifest_dir.join("../shatter-rust/target/debug/shatter-rust");
 23→    if standalone.exists() {
 24→        return standalone;
 25→    }
 26→    let workspace = manifest_dir.join("../target/debug/shatter-rust");
 27→    if workspace.exists() {
 28→        return workspace;
 29→    }
 30→    panic!(
 31→        "Rust frontend not built. Run `cargo build --manifest-path shatter-rust/Cargo.toml`.\n\
 32→         Checked: {}\n         {}",
 33→        standalone.display(),
 34→        workspace.display()
 35→    );
 36→}
 37→
 38→/// Path to the Rust example source files.
 39→fn rust_examples_dir() -> PathBuf {
 40→    let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
 41→    manifest_dir.join("../examples/rust/src")
 42→}
 43→
 44→/// Spawn a real Rust frontend subprocess with SHATTER_RUNTIME_PATH set
 45→/// so the executor can find the runtime crate for compilation.
 46→async fn spawn_rust_frontend() -> Frontend {
 47→    let frontend_path = rust_frontend_path();
 48→
 49→    let manifest_dir = Path::new(env!("CARGO_MANIFEST_DIR"));
 50→    let runtime_path = manifest_dir.join("../shatter-rust-runtime");
 51→    assert!(
 52→        runtime_path.join("Cargo.toml").exists(),
 53→        "shatter-rust-runtime not found at {}",
 54→        runtime_path.display()
 55→    );
 56→
 57→    let mut config = FrontendConfig::new(frontend_path);
 58→    // Rust frontend compiles per execution, so allow generous timeouts.
 59→    config.request_timeout = std::time::Duration::from_secs(120);
 60→    config.env_vars.push((
 61→        "SHATTER_RUNTIME_PATH".to_string(),
 62→        runtime_path.to_string_lossy().into_owned(),
 63→    ));
 64→    config.env_vars.push((
 65→        "SHATTER_EXEC_TIMEOUT".to_string(),
 66→        "60".to_string(),
 67→    ));
 68→
 69→    Frontend::spawn(&config)
 70→        .await
 71→        .expect("failed to spawn Rust frontend")
 72→}
