 74→/// Analyze a function and return its analysis.
 75→async fn analyze_function(
 76→    frontend: &mut Frontend,
 77→    file: &str,
 78→    function_name: &str,
 79→) -> FunctionAnalysis {
 80→    let response = frontend
 81→        .send(ProtoCommand::Analyze {
 82→            file: file.to_string(),
 83→            function: Some(function_name.to_string()),
 84→            project_root: None,
 85→        })
 86→        .await
 87→        .expect("analyze command failed");
 88→
 89→    match response.result {
 90→        ResponseResult::Analyze { functions } => functions
 91→            .into_iter()
 92→            .find(|f| f.name == function_name)
 93→            .unwrap_or_else(|| {
 94→                panic!("function '{function_name}' not found in analysis results")
 95→            }),
 96→        other => panic!("expected Analyze response, got: {other:?}"),
 97→    }
 98→}
 99→
100→/// Instrument a function and assert success.
101→async fn instrument_function(frontend: &mut Frontend, file: &str, function_name: &str) {
102→    let response = frontend
103→        .send(ProtoCommand::Instrument {
104→            file: file.to_string(),
105→            function: function_name.to_string(),
106→            mocks: vec![],
107→            project_root: None,
108→        })
109→        .await
110→        .expect("instrument command failed");
111→
112→    match response.result {
113→        ResponseResult::Instrument { instrumented, .. } => {
114→            assert!(instrumented, "instrumentation returned false");
115→        }
116→        ResponseResult::Error { code, message, .. } => {
117→            panic!("instrument error ({code:?}): {message}");
118→        }
119→        other => panic!("expected Instrument response, got: {other:?}"),
120→    }
121→}
122→
123→/// Execute a function with given inputs via the raw protocol.
124→///
125→/// The Rust frontend's Execute command requires a `file` field (unlike TS/Go
126→/// frontends that hold instrumented code in memory). We send a raw JSON request
127→/// to include the file path.
128→async fn execute_function_raw(
129→    frontend: &mut Frontend,
130→    file: &str,
131→    function_name: &str,
132→    inputs: Vec<serde_json::Value>,
133→) -> shatter_core::protocol::ExecuteResult {
134→    // Build raw JSON request with the file field included.
135→    let request_json = serde_json::json!({
136→        "protocol_version": "0.1.0",
137→        "id": 0,  // will be overridden by send_raw
138→        "command": "execute",
139→        "file": file,
140→        "function": function_name,
141→        "inputs": inputs,
142→        "mocks": []
143→    });
144→
145→    let response = frontend
146→        .send_raw(request_json)
147→        .await
148→        .expect("execute command failed");
149→
150→    match response.result {
151→        ResponseResult::Execute(result) => *result,
152→        ResponseResult::Error { code, message, .. } => {
153→            panic!("execute error ({code:?}): {message}");
154→        }
155→        other => panic!("expected Execute response, got: {other:?}"),
156→    }
157→}
158→
159→/// Collect distinct return value strings from a set of execution results.
160→fn collect_return_values(
161→    results: &[shatter_core::protocol::ExecuteResult],
162→) -> HashSet<String> {
163→    results
164→        .iter()
165→        .map(|exec| {
166→            if let Some(ref err) = exec.thrown_error {
167→                format!("ERROR:{}", err.message)
168→            } else {
169→                match &exec.return_value {
170→                    Some(v) => v.to_string(),
171→                    None => "null".to_string(),
172→                }
173→            }
174→        })
175→        .collect()
176→}
