31→export function compareMagnitudes(a: number, b: number): string {
32→    const sum = a + b;
33→    const product = a * b;
34→
35→    if (sum > 100) {
36→        if (product > 1000) {
37→            return "both-large";
38→        }
39→        return "sum-large";
40→    }
41→    if (product > 1000) {
42→        return "product-large";
43→    }
44→    return "both-small";
45→}
