 1→// Example 4: Functions with error throwing
 2→// Tests shatter's ability to discover error paths and distinguish normal vs exceptional returns.
 3→
 4→// EXPECTED BRANCHES:
 5→//   1. denominator === 0                   → throws Error("division by zero")
 6→//   2. !isFinite(numerator)                → throws Error("non-finite numerator")
 7→//   3. result is integer                   → returns integer result
 8→//   4. result is not integer               → returns float result
 9→
10→export function safeDivide(numerator: number, denominator: number): number {
11→    if (denominator === 0) {
12→        throw new Error("division by zero");
13→    }
14→    if (!isFinite(numerator)) {
15→        throw new Error("non-finite numerator");
16→    }
17→    const result = numerator / denominator;
18→    if (Number.isInteger(result)) {
19→        return result;
20→    }
21→    return result;
22→}
23→
24→// EXPECTED BRANCHES:
25→//   1. items is empty                → throws Error("empty array")
26→//   2. any item < 0                  → throws Error("negative value")
27→//   3. all items === 0               → returns { sum: 0, avg: 0, max: 0 }
28→//   4. normal case, max > 100        → returns stats with "high-max" flag
29→//   5. normal case, max <= 100       → returns stats without flag
30→
31→export function computeStats(items: number[]): {
32→    sum: number;
33→    avg: number;
34→    max: number;
35→    flag?: string;
36→} {
37→    if (items.length === 0) {
38→        throw new Error("empty array");
39→    }
40→
41→    let sum = 0;
42→    let max = items[0];
43→
44→    for (const item of items) {
45→        if (item < 0) {
46→            throw new Error("negative value");
47→        }
48→        sum += item;
49→        if (item > max) {
50→            max = item;
51→        }
52→    }
53→
54→    const avg = sum / items.length;
55→
56→    if (max === 0) {
57→        return { sum: 0, avg: 0, max: 0 };
58→    }
59→
60→    if (max > 100) {
61→        return { sum, avg, max, flag: "high-max" };
62→    }
63→
64→    return { sum, avg, max };
65→}
