 1→// Example 15: Email address validator
 2→// Validates email addresses against a subset of RFC 5321/5322 rules.
 3→// Exercises character-class checks, length limits, and structural validation —
 4→// a common utility with many subtle edge cases.
 5→//
 6→// EXPECTED BRANCHES for validateEmail (20):
 7→//   1. empty string                             → { valid: false, reason: "empty" }
 8→//   2. no '@' character                         → { valid: false, reason: "missing @" }
 9→//   3. multiple '@' characters                  → { valid: false, reason: "multiple @" }
10→//   4. local part empty                         → { valid: false, reason: "empty local part" }
11→//   5. local part > 64 chars                    → { valid: false, reason: "local part too long" }
12→//   6. domain empty                             → { valid: false, reason: "empty domain" }
13→//   7. domain > 253 chars                       → { valid: false, reason: "domain too long" }
14→//   8. local starts with dot                    → { valid: false, reason: "local starts with dot" }
15→//   9. local ends with dot                      → { valid: false, reason: "local ends with dot" }
16→//  10. local has consecutive dots               → { valid: false, reason: "consecutive dots" }
17→//  11. local has invalid character              → { valid: false, reason: "invalid character in local" }
18→//  12. domain has no dot (no TLD)               → { valid: false, reason: "domain missing TLD" }
19→//  13. domain label starts with hyphen          → { valid: false, reason: "domain label starts with hyphen" }
20→//  14. domain label ends with hyphen            → { valid: false, reason: "domain label ends with hyphen" }
21→//  15. domain label empty (consecutive dots)    → { valid: false, reason: "empty domain label" }
22→//  16. domain label > 63 chars                  → { valid: false, reason: "domain label too long" }
23→//  17. domain has invalid character             → { valid: false, reason: "invalid character in domain" }
24→//  18. plus-addressing detected                 → { valid: true, tag: "..." }
25→//  19. quoted local part (starts+ends with ")   → { valid: true, quoted: true }
26→//  20. standard valid address                   → { valid: true }
27→//
28→// DIFFICULTY: Hard. Many branches require precise string construction —
29→// specific characters at specific positions. Random generation rarely produces
30→// structurally valid emails, let alone ones that trigger each validation branch.
31→
32→interface EmailResult {
33→    valid: boolean;
34→    reason?: string;
35→    tag?: string;
36→    quoted?: boolean;
37→}
38→
39→const LOCAL_PART_MAX = 64;
40→const DOMAIN_MAX = 253;
41→const DOMAIN_LABEL_MAX = 63;
42→
43→const VALID_LOCAL_CHARS = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]$/;
44→const VALID_DOMAIN_CHARS = /^[a-zA-Z0-9-]$/;
45→
46→export function validateEmail(email: string): EmailResult {
47→    if (email.length === 0) {
48→        return { valid: false, reason: "empty" };
49→    }
50→
51→    const atIdx = email.indexOf("@");
52→    if (atIdx === -1) {
53→        return { valid: false, reason: "missing @" };
54→    }
55→    if (email.indexOf("@", atIdx + 1) !== -1) {
56→        return { valid: false, reason: "multiple @" };
57→    }
58→
59→    const local = email.slice(0, atIdx);
60→    const domain = email.slice(atIdx + 1);

